import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"Activation Onboarding Guide","description":"","frontmatter":{"title":"Activation Onboarding Guide","slug":"activation-onboarding-guide"},"headers":[],"relativePath":"marketer-hub/activation-onboarding-guide.md","filePath":"marketer-hub/activation-onboarding-guide.md"}'),i={name:"marketer-hub/activation-onboarding-guide.md"};function n(s,e,d,l,h,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Welcome to <a href="https://help.branch.io/docs/products#activation" target="_blank" rel="noreferrer">Branch Activation</a>, our enterprise solution for creating custom QR Codes and Short Links to activate customers across web and app.</p><p>With Activation, you can create shortened web and app links, as well as custom QR codes, that leverage the full power of the Branch Growth Platform.</p><p>Activation simplifies how you generate branded web links, app links, and QR codes, providing dedicated click insights and exports without requiring complex SDK setups for your web campaigns.</p><p>The information and resources in this guide will help you:</p><ul><li>Set up your Branch Dashboard</li><li>Choose the right link creation method for your use case</li><li>Test and manage your links</li><li>View and export your data</li></ul><h3 id="how-branch-links-work" tabindex="-1">How Branch Links work <a class="header-anchor" href="#how-branch-links-work" aria-label="Permalink to &quot;How Branch Links work&quot;">​</a></h3><p>Web Links are web-only Short Links that work everywhere. App Links are deep links that take users to specific pages in your app. Web and App Links look the same (yourbrand.com/slug or yourbrand.app.link/slug) depending on if you choose to use a custom domain or a Branch-provided app.link domain.</p><h4 id="expected-behavior-for-web-links" tabindex="-1">Expected behavior for Web Links <a class="header-anchor" href="#expected-behavior-for-web-links" aria-label="Permalink to &quot;Expected behavior for Web Links&quot;">​</a></h4><p>If your end user does <strong>not</strong> have your app installed, or if you don’t have an app, the link will open in their default web browser. If they do have your app downloaded, the link will open in your app through an in-app web view.</p><h4 id="expected-behavior-for-app-links" tabindex="-1">Expected behavior for App Links <a class="header-anchor" href="#expected-behavior-for-app-links" aria-label="Permalink to &quot;Expected behavior for App Links&quot;">​</a></h4><p>If your end user has your app installed, the App Link will deep link to the specific app page you’ve chosen. If they do <strong>not</strong> have your app installed, they will taken to the redirect destination for non-app users which can be configured as a web page, a Branch Deepview, or the app store listing to download the app.</p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>The questions in this section will help you decide how you want to set up Activation for your scenario. The questions you’ll need to answer depend on whether you are a new or existing Branch user.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>To show an in-app web view for web links when a user has your app downloaded, you must update your Branch SDK to version 3.12.0 or higher for iOS and 5.18.0 for Android. If you don’t update the SDK, your app’s homepage will open using Android App Linking or Apple Universal Links.</p></div><h3 id="new-branch-users" tabindex="-1">New Branch users <a class="header-anchor" href="#new-branch-users" aria-label="Permalink to &quot;New Branch users&quot;">​</a></h3><p>If you are a new Branch user, start by answering the following questions:</p><ol><li><p>Will you be using <strong>a custom domain or a Branch-provided</strong> <code>app.link</code> <strong>domain</strong>?</p><ul><li><p>If you want to use a custom domain, read our <a href="./basic-link-configuration.html">Basic Link Configuration</a> article to learn how to set it up.</p><ul><li>You can also add multiple custom domains to use for different purposes.</li></ul></li><li><p>If you use the Branch-provided domain, your links will have the format <code>yourbrand.app.link</code> after implementation.</p></li></ul></li><li><p>Will you be creating <strong>web links, app links, or both</strong>? You can learn more in our <a href="./create-web-links.html">Create Web Links</a> or <a href="./create-app-links.html">Create App Links</a> articles.</p><ol><li><p>If you’re creating app links with the intention of deep linking, you must integrate the <a href="https://help.branch.io/developers-hub/docs/native-sdks-overview" target="_blank" rel="noreferrer">Branch SDK</a> with your app.</p></li><li><p>If you’re creating both, do you want to <strong>consolidate to the same domain for web and app linking or keep them separate</strong>?</p><ol><li>Learn more about the implications of consolidating or separating your web and app linking domains in the <a href="./activation-onboarding-guide.html#choose-web-and-app-domains">&quot;Choose web and app domains&quot;</a> section below.</li></ol></li></ol></li></ol><h3 id="existing-branch-users" tabindex="-1">Existing Branch users <a class="header-anchor" href="#existing-branch-users" aria-label="Permalink to &quot;Existing Branch users&quot;">​</a></h3><p>If you are an existing Branch user, start by answering the following questions:</p><ol><li><p>Will you continue using <strong>the same domain with Branch for shortened links or a different domain</strong>?</p><ol><li><p>If you choose to use your existing domain for all links, then Activation will be enabled for your current Branch Dashboard.</p></li><li><p>If you want to <a href="./advanced-link-configuration.html">use a different domain</a> from your current Branch domain, do you also want to <strong>consolidate to the same domain for web and app linking or keep them separate</strong>?</p><ol><li>Learn more about the implications of consolidating or separating your web and app linking domains in the <a href="./activation-onboarding-guide.html#choose-web-and-app-domains">&quot;Choose web and app domains&quot;</a> section below.</li></ol></li></ol></li><li><p>Will you be creating <strong>web links, app links, or both</strong>? You can learn more in our <a href="./create-web-links.html">Create Web Links</a> or <a href="./create-app-links.html">Create App Links</a> articles.</p><ol><li>If you’re creating app links with the intention of deep linking, you must integrate the <a href="https://help.branch.io/developers-hub/docs/native-sdks-overview" target="_blank" rel="noreferrer">Branch SDK</a> with your app.</li></ol></li></ol><h3 id="choose-web-and-app-domains" tabindex="-1">Choose web and app domains <a class="header-anchor" href="#choose-web-and-app-domains" aria-label="Permalink to &quot;Choose web and app domains&quot;">​</a></h3><p>Read the following sections to review the implications of using either the same or different web and app domains when shortening links with Activation.</p><h4 id="different-web-and-app-domains" tabindex="-1">Different web and app domains <a class="header-anchor" href="#different-web-and-app-domains" aria-label="Permalink to &quot;Different web and app domains&quot;">​</a></h4><ul><li><strong>All web links will open using the user’s default browser</strong>, regardless of whether they have the app.</li><li><strong>You can’t toggle between web and app destinations without using a different domain</strong>. This means the web and app links, and the QR code would have to be updated manually if you switch between a web and app destination after you’ve already deployed the link.</li></ul><h4 id="same-web-and-app-domains" tabindex="-1">Same web and app domains <a class="header-anchor" href="#same-web-and-app-domains" aria-label="Permalink to &quot;Same web and app domains&quot;">​</a></h4><ul><li><strong>Web links will open in an in-app web view</strong> when users who already have your app click on a shortened web link.</li><li><strong>You can toggle between web and app destinations without changing the Branch Link URL</strong>. This allows you to update links after you deploy them. Imagine you have a Branch Link that goes to a webpage because the corresponding page doesn’t exist in the app. Once the app is updated to include that page, the link settings can be updated to go to an in-app destination without the need to update the QR code or Branch Link URL.</li></ul><h2 id="create-links" tabindex="-1">Create links <a class="header-anchor" href="#create-links" aria-label="Permalink to &quot;Create links&quot;">​</a></h2><p>Use the resources listed in this section to help you create links individually or in bulk.</p><p>Based on your desired link behavior and variety, use the following resources to help you create links:</p><ul><li><a href="./create-web-links.html">Create Web Links</a></li><li><a href="./create-app-links.html">Create App Links</a> (requires developer support)</li><li><a href="./creating-a-deep-link.html">Deep Link Reference</a></li><li><a href="https://help.branch.io/apidocs/deep-linking-api" target="_blank" rel="noreferrer">Deep Linking API</a> (requires developer support)</li></ul><p>Use the optional analytics tags fields to assign values to channel, feature, and campaign relevant to your marketing goals. These values will be used for filtering your link analytics.</p><p>To explore these concepts further, check out the following Branch University courses:</p><ul><li><a href="https://university.branch.io/paths/5096b210-eae4-11ee-bdd2-0293a0258cb5" target="_blank" rel="noreferrer">Link Creation &amp; Management Made Easy</a></li><li><a href="https://university.branch.io/paths/7f3f266c-3705-11ee-a8fb-06ea1e01ee1b" target="_blank" rel="noreferrer">Engagement: Short Links</a></li><li><a href="https://university.branch.io/paths/019098ae-8594-7ff1-9be2-aabf91cc4426" target="_blank" rel="noreferrer">Seamless Branding: Custom QR Codes</a></li></ul><h2 id="test-links" tabindex="-1">Test links <a class="header-anchor" href="#test-links" aria-label="Permalink to &quot;Test links&quot;">​</a></h2><p>Use <a href="./link-validator.html">Link Validator</a> to test how your link will behave based on who your end user is and where they are clicking the link from.</p><h2 id="export-campaign-data" tabindex="-1">Export campaign data <a class="header-anchor" href="#export-campaign-data" aria-label="Permalink to &quot;Export campaign data&quot;">​</a></h2><p>With Activation, you can export your campaign data using Dashboard Exports, Branch’s Advanced Data Feeds, or one of the APIs included in your package.</p><h4 id="branch-dashboard" tabindex="-1">Branch Dashboard <a class="header-anchor" href="#branch-dashboard" aria-label="Permalink to &quot;Branch Dashboard&quot;">​</a></h4><p>Export data as a CSV or JSON file manually from the Branch Dashboard using <a href="./dashboard-exports.html">Dashboard Exports</a>. Choose between Daily or Custom exports to identify the best configuration of your export.</p><h4 id="included-apis" tabindex="-1">Included APIs <a class="header-anchor" href="#included-apis" aria-label="Permalink to &quot;Included APIs&quot;">​</a></h4><p>Activation includes the <a href="https://help.branch.io/apidocs/daily-exports-api" target="_blank" rel="noreferrer">Daily Exports API</a>, <a href="https://help.branch.io/apidocs/custom-exports-api" target="_blank" rel="noreferrer">Custom Exports API</a>, <a href="https://help.branch.io/apidocs/query-api" target="_blank" rel="noreferrer">Query API</a>, <a href="https://help.branch.io/apidocs/aggregate-api" target="_blank" rel="noreferrer">Aggregate API</a>, and <a href="https://help.branch.io/apidocs/cohort-api" target="_blank" rel="noreferrer">Cohort API</a>. Use these APIs to export specific data and analytics.</p><details><summary>Available export fields</summary><p>The following table shows the export fields that are available with Activation:</p><table tabindex="0"><thead><tr><th>Field name</th></tr></thead><tbody><tr><td>di_match_click_token</td></tr><tr><td>event_timestamp</td></tr><tr><td>hash_version</td></tr><tr><td>id</td></tr><tr><td>last_attributed_touch_data_custom_fields</td></tr><tr><td>last_attributed_touch_data_dollar_marketing_title</td></tr><tr><td>last_attributed_touch_data_plus_current_feature</td></tr><tr><td>last_attributed_touch_data_plus_touch_id</td></tr><tr><td>last_attributed_touch_data_plus_url</td></tr><tr><td>last_attributed_touch_data_plus_via_features</td></tr><tr><td>last_attributed_touch_data_plus_web_format</td></tr><tr><td>last_attributed_touch_data_tilde_campaign</td></tr><tr><td>last_attributed_touch_data_tilde_campaign_id</td></tr><tr><td>last_attributed_touch_data_tilde_campaign_type</td></tr><tr><td>last_attributed_touch_data_tilde_channel</td></tr><tr><td>last_attributed_touch_data_tilde_customer_campaign</td></tr><tr><td>last_attributed_touch_data_tilde_feature</td></tr><tr><td>last_attributed_touch_data_tilde_id</td></tr><tr><td>last_attributed_touch_data_tilde_keyword</td></tr><tr><td>last_attributed_touch_data_tilde_keyword_id</td></tr><tr><td>last_attributed_touch_data_tilde_keyword_match_type</td></tr><tr><td>last_attributed_touch_data_tilde_placement</td></tr><tr><td>last_attributed_touch_data_tilde_stage</td></tr><tr><td>last_attributed_touch_data_tilde_tags</td></tr><tr><td>last_attributed_touch_timestamp</td></tr><tr><td>last_attributed_touch_timestamp_iso</td></tr><tr><td>name</td></tr><tr><td>origin</td></tr><tr><td>request_id</td></tr><tr><td>timestamp</td></tr><tr><td>timestamp_iso</td></tr><tr><td>user_data_brand</td></tr><tr><td>user_data_browser</td></tr><tr><td>user_data_build</td></tr><tr><td>user_data_cpu_type</td></tr><tr><td>user_data_cross_platform_id</td></tr><tr><td>user_data_developer_identity</td></tr><tr><td>user_data_environment</td></tr><tr><td>user_data_geo_city_code</td></tr><tr><td>user_data_geo_city_en</td></tr><tr><td>user_data_geo_country_code</td></tr><tr><td>user_data_geo_dma_code</td></tr><tr><td>user_data_http_referrer</td></tr><tr><td>user_data_installer_package_name</td></tr><tr><td>user_data_internet_connection_type</td></tr><tr><td>user_data_ip</td></tr><tr><td>user_data_language</td></tr><tr><td>user_data_limit_ad_tracking</td></tr><tr><td>user_data_model</td></tr><tr><td>user_data_opted_in</td></tr><tr><td>user_data_os</td></tr><tr><td>user_data_os_version</td></tr><tr><td>user_data_os_version_android</td></tr><tr><td>user_data_past_cross_platform_ids</td></tr><tr><td>user_data_platform</td></tr><tr><td>user_data_prob_cross_platform_ids</td></tr><tr><td>user_data_screen_height</td></tr><tr><td>user_data_screen_width</td></tr><tr><td>user_data_user_agent</td></tr></tbody></table></details><h4 id="advanced-data-feeds" tabindex="-1">Advanced Data Feeds <a class="header-anchor" href="#advanced-data-feeds" aria-label="Permalink to &quot;Advanced Data Feeds&quot;">​</a></h4><p><a href="./data-feeds-overview.html">Advanced Data Feeds</a> is Branch’s suite of tools for exporting data which can be added on to any Branch <a href="./packaging.html">package</a>. Use these tools if you want to export your data to other analytics services.</p><p>To explore these concepts further, check out these blog posts:</p><ul><li><a href="https://www.branch.io/resources/blog/which-branch-data-export-solution-should-i-use-2/" target="_blank" rel="noreferrer">Which Branch Data Export Solution Should I Use?</a></li><li><a href="https://www.branch.io/resources/blog/10-essential-tips-for-leveraging-branchs-analytics-capabilities/" target="_blank" rel="noreferrer">10 Essential Tips for Leveraging Branch’s Analytics Capabilities</a></li></ul><h2 id="manage-and-maintain-links" tabindex="-1">Manage and maintain links <a class="header-anchor" href="#manage-and-maintain-links" aria-label="Permalink to &quot;Manage and maintain links&quot;">​</a></h2><p>Use <a href="./linkhub.html">LinkHub</a> to create, manage, and deploy links at scale. You can also view click analytics for your links on the <a href="./branch-summary-page.html">Overview</a> page.</p><p>Use <a href="./link-templates.html">Link Templates</a> to manage the bulk creation of your app and web Short Links. A Link Template can be used to automatically apply attributes while creating Short Links. This can save you time and reduce the potential for errors when creating Short Links.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>Can I change the link type from app to web and the other way around?</summary><p>Yes. A link created as an app link can be switched to a web link and the other way around. The method you use to create the link does not matter when switching between app and web links.</p></details><details><summary>Do I need to integrate the Branch SDK to use Activation?</summary><p>Only if you want to create app links or support in-app webviews for web links.</p></details><details><summary>Do shortened links expire?</summary><p>Short Links created in the Branch Dashboard will never expired, even if archived. Links created with the Deep Linking API will expire 380 days after creation or the last time a user clicked it.</p></details><details><summary>I am currently using Branch web-only links. Can I continue using those links?</summary><p>No. There is no need to migrate existing web-only links. They will continue to function as expected. Once you update the Branch SDK to the latest version (Branch SDK version ≥ 3.12.0 on iOS, ≥ 5.18.0 on Android), web links will open an in-app webview for users with your app installed. Non-app users will be taken to the device browser.</p></details><details><summary>What should I do if I don’t have the team or resources needed to implement Activation?</summary><p>If your team lacks the capacity or expertise to implement the solution, our <a href="https://www.branch.io/professional-services/" target="_blank" rel="noreferrer">Professional Services</a> team can provide hands-on, tailored support to ensure a successful deployment from start to finish. We offer advisory hours to give you access to our consultants for strategic guidance, technical support, or specific project deliverables.</p></details><h2 id="get-professional-services-support" tabindex="-1">Get Professional Services support <a class="header-anchor" href="#get-professional-services-support" aria-label="Permalink to &quot;Get Professional Services support&quot;">​</a></h2><p>Branch’s <a href="https://www.branch.io/professional-services/" target="_blank" rel="noreferrer">Professional Services</a> team is available on a paid basis for your onboarding setup and advisory, implementation enhancement, and large strategic project execution needs. Reach out to your Branch Account Owner for more information on how Professional Services can support your Activation product usage.</p><h2 id="leverage-branch-university" tabindex="-1">Leverage Branch University <a class="header-anchor" href="#leverage-branch-university" aria-label="Permalink to &quot;Leverage Branch University&quot;">​</a></h2><p>For continued learning, <a href="https://university.branch.io" target="_blank" rel="noreferrer">Branch University</a> offers live, <a href="https://university.branch.io/pages/live-trainings" target="_blank" rel="noreferrer">expert-led training sessions</a> designed to help you master our products, sharpen your skills, and gain hands-on experience. These sessions provide an opportunity to ask questions directly to our trainers, ensuring you get the most out of the Branch Growth Platform.</p>',60)])])}const b=t(i,[["render",n]]);export{c as __pageData,b as default};
